oxy_webhelp_navlinks = {"tocId-d27248e1537":{"topics":[{"title":"Rubrik clusters","shortdesc":"<p class=\"shortdesc\">A Rubrik cluster is an instance of Rubrik CDM running on any virtual or physical         platform. You can add the Rubrik cluster to <span class=\"ph\">RSC<\/span> to enable extended features         for the cluster.<\/p>","href":"saas\/common\/rubrik_clusters_2.html","attributes":{"data-id":"rubrik_clusters"},"menu":{"hasChildren":true},"tocID":"rubrik_clusters-d27248e1543","next":"rubrik_clusters-d27248e1543"},{"title":"Rubrik CDM Install and Upgrade Guide","href":"install\/rsc_cluster_deployment.html","menu":{"hasChildren":true},"tocID":"tocId-d27248e2271","next":"tocId-d27248e2271"},{"title":"Security","shortdesc":"<p class=\"shortdesc\"><span class=\"ph\">Rubrik Security Cloud<\/span> provides end-to-end security for data management         information.<\/p>","href":"saas\/common\/security.html","attributes":{"data-id":"security"},"menu":{"hasChildren":true},"tocID":"security-d27248e3486","next":"security-d27248e3486"},{"title":"Data Sources","shortdesc":"<p class=\"shortdesc\">You can add hosts, instances, and servers for various data-center workloads in the         Data Sources menu. Additionally, you can configure access credentials by setting up Guest OS         settings and SMB security.<\/p>","href":"saas\/data_sources.html","attributes":{"data-id":"data_sources"},"menu":{"hasChildren":true},"tocID":"data_sources-d27248e3549","next":"data_sources-d27248e3549"},{"title":"Rubrik Cloud Cluster Elastic Storage ","shortdesc":"<p class=\"shortdesc\">You can use <span class=\"ph\">Rubrik Security Cloud<\/span> to provision a Rubrik Cloud Cluster Elastic         Storage deployment.<\/p>","href":"saas\/rubrik_cc_es_on_saas.html","attributes":{"data-id":"rubrik_cc_es_on_saas"},"menu":{"hasChildren":true},"tocID":"rubrik_cc_es_on_saas-d27248e4110","next":"rubrik_cc_es_on_saas-d27248e4110"}]}};